-- Generated by shared/service_mapping/generate_seed_sql.py
-- CRM GUI service mapping: pages registry + per-product seed + view + legacy drop
BEGIN;

DROP VIEW IF EXISTS v_gui_crm_product_mapping CASCADE;
DROP TABLE IF EXISTS gui_crm_service_mapping_seed CASCADE;
DROP TABLE IF EXISTS gui_crm_service_mapping_override CASCADE;
DROP TABLE IF EXISTS gui_crm_service_pages CASCADE;

CREATE TABLE gui_crm_service_pages (
    page_key          TEXT PRIMARY KEY,
    category_label    TEXT NOT NULL,
    gui_tab_binding   TEXT NOT NULL,
    resource_unit     TEXT NOT NULL DEFAULT 'Adet',
    icon              TEXT,
    route_hint        TEXT,
    tab_hint          TEXT,
    sub_tab_hint      TEXT
);


CREATE TABLE gui_crm_service_mapping_seed (
    productid   TEXT PRIMARY KEY,
    page_key    TEXT NOT NULL REFERENCES gui_crm_service_pages(page_key)
);


CREATE TABLE gui_crm_service_mapping_override (
    productid    TEXT PRIMARY KEY,
    page_key     TEXT NOT NULL REFERENCES gui_crm_service_pages(page_key),
    notes        TEXT,
    updated_by   TEXT,
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

DO $migrate_manual$
BEGIN
  IF to_regclass('public.discovery_crm_product_category_alias') IS NOT NULL THEN
    SELECT pca.productid,
           CASE WHEN pca.category_code IN (SELECT page_key FROM gui_crm_service_pages)
                THEN pca.category_code ELSE 'other' END,
           COALESCE(pca.notes, 'migrated from discovery_crm_product_category_alias'),
           'migration',
           now()
    FROM   discovery_crm_product_category_alias pca
    WHERE  pca.source = 'manual';
  END IF;
END $migrate_manual$;

CREATE OR REPLACE VIEW v_gui_crm_product_mapping AS
SELECT
    pr.productid,
    pr.name AS product_name,
    pr.productnumber AS product_number,
    COALESCE(o.page_key, s.page_key, 'other') AS category_code,
    pg.category_label,
    pg.gui_tab_binding,
    NULL::text AS resource_unit,
    CASE WHEN o.productid IS NOT NULL THEN 'override' WHEN s.productid IS NOT NULL THEN 'yaml' ELSE 'default' END AS mapping_source,
    COALESCE(NULLIF(TRIM(pg.resource_unit), ''), 'Adet') AS page_resource_unit
FROM   discovery_crm_products pr
LEFT JOIN gui_crm_service_mapping_seed s ON s.productid = pr.productid
LEFT JOIN gui_crm_service_mapping_override o ON o.productid = pr.productid
JOIN   gui_crm_service_pages pg ON pg.page_key = COALESCE(o.page_key, s.page_key, 'other');

DROP TABLE IF EXISTS discovery_crm_product_category_alias CASCADE;

COMMIT;
